        } else if uf.rank[rx] > uf.rank[ry] {
            uf.parent[ry] = rx
        } else {
            uf.parent[ry] = rx
            uf.rank[rx]++
        }
        uf.comp--
    }

    connected := func(uf *UF, x, y int64) bool {
        return find(uf, x) == find(uf, y)
    }

    clone := func(uf *UF) *UF {
        p := make([]int64, len(uf.parent))
        r := make([]int64, len(uf.rank))
        copy(p, uf.parent)
        copy(r, uf.rank)
        return &UF{p, r, uf.comp}
    }

    ufAll := NewUF(n)
    for _, e := range edges {
